INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('purgatory', 'ceb', 'salvation', 'Purgaturyo', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa purgaturyo?', '"Ang Sta. Iglesya nagtudlo nga gawas sa usa ka dapit sa hingpit nga kalipay nga dulngan sa mga matarong nga mao ang langit ug sa dapit sa walay kataposang silot nga dulngan sa mga dautan nga mao ang impyerno dunay usa ka tunga-tunga nga dapit o kahimtang nga dulngan sa mga kalag nga namatay diha sa kahimtang sa gagmayng sala o niadtong wala pa hingpit makabayad sa kastigo temporal gumikan sa sala. Kining maong dapit kasagaran gitawag kini og purgaturyo. Ang Sta. Iglesya nagtudlo pa gayod nga ang mga kalag sa purgaturyo nag-antos ug mahimo silang katabangan pinaagi sa pag-ampo sa mga buhi labi na gyod sa Santos nga Sakripisyo sa Misa.\n\nSa atong pagtuon sa Biblia dili kanunay nga pangitaon nato letra por letra ang usa ka panudlo kondili kinahanglan usab nga sabton nato ang atong gibasa: “Kay siya ang naghimo kanamong takos sa pag-alagad sa bag-ong kasabotan nga dili balaod nga sinulat kondili iya sa Espiritu” (2 Cor. 3:6). “Mihatag silag binaba nga hubad sa Balaod sa Dios, ug gipasabot kini aron ang mga tawo makasabot niini” (Neh. 8:8). “Ang maalamon angay nga mosabot sa nahisulat dinhi ug ang masinabuton angay masayod niini” (Oseas 14:9). Ang pagtulon-an mahitungod sa purgaturyo klaro nga gitudlo sa Daang Tugon. Tapos sa usa ka gubat diin dunay mga Judio nga nangamatay, si Judas Macabeo nga nangulo kanila naghimog halad alang sa sala niadtong nangamatay: “Nagpaamot usab siya gikan sa tanan niyang mga tawo, nga mikabat ug 2,000 ka salapi nga plata, ug gipadala kini ngadto sa Jerusalem aron gamiton alang sa usa ka halad alang sa sala. Si Judas naghimo niining hamili nga butang tungod kay nagtuo siya sa pagkabanhaw. Kon wala pa siya magtuo nga ang patay mabanhaw, usa unta ka butang nga binoang ug walay kapuslanan ang pag-ampo alang kanila. Niining malig-on ug diosnon nga hunahuna nga ang tanang mga tawo nga nagtuo sa Dios makadawat sa usa ka ganti nga katingalahan, si Judas nangandam alang sa usa ka halad alang sa sala aron malingkawas sa ilang mga sala sila nga nangamatay” (2 Mac. 12:43-45). Kini nga hitabo nagtudlo kanato sa tulo ka hinungdanong butang: Una- nga gibansay sa katawhan sa Dios ang pag-ampo alang sa ilang mga minatay. Ikaduha- giingon nga ang maong mga pag-ampo maayo ug mapuslanon. Ikatulo- nga ang tuyo sa maong mga pag-ampo aron sila nga nangamatay mabadbaran sa ilang mga sala. Kining pag-ampo alang sa mga minatay nagpasabot nga dunay kahimtang sa mga kalag sa sunod nga kinabuhi nga mahimo pang katabangan sa mga pag-ampo. Karon ang mga kalag nga atua na sa langit wala na magkinahanglan pa sa mga pag-ampo ug ang mga kalag nga atua sa impyerno dili na sab matabangan pa sa mga pag-ampo. Kining maong dapit o kahimtang mao ang gitawag og purgaturyo.\nPag-abot ni Cristo diha sa Bag-ong Tugon, gibadlong ba niya ang mga Judio sa ilang gihimo nga pag-ampo alang sa mga nangamatay? Wala gayod! Hinunoa, si Jesus nagpasabot niini sa iyang pag-ingon: “Ang makasala batok sa Anak sa Tawo mapasaylo, apan ang makasala batok sa Espiritu Santo dili mapasaylo niining kinabuhi o bisan sa sunod nga kinabuhi” (Mat. 12:32). Sa pag-ingon ni Jesus nga ang sala batok sa Espiritu Santo dili mapasaylo bisan sa sunod nga kinabuhi, masabot nato nga duna diay mga sala nga mahimo pa nga mapasaylo sa sunod nga kinabuhi. Karon ang mga sala dili mapasaylo didto sa langit kay wala may mahugaw nga makasulod sa langit ug ang mga sala dili na sab mapasaylo didto sa impyerno tungod kay wala na man didtoy kaluwasan. Busa ang mga gagmayng mansa o buling nga mitapot sa kalag sa takna sa kamatayon pasayloon kini o linisan didto sa purgaturyo. Si San Pablo nagpasabot usab sa pagka-dunay purgaturyo sa iyang pag-ingon: “Sa adlaw ang Ginoo ang buhat sa tagsatagsa ipadayag. Sulayan kini sa kalayo ug sutaon ang iyang matuod nga kalidad. Kon ang iyang buhat hingpit siya makaangkon og ganti, apan kon ang iyang buhat dili hingpit siya mag-antos sa kapildihan apan siya maluwas, wala sapayan nga moagi siya sa kalayo” (1 Cor. 3:13-15). Kining maong kahimtang sa sunod nga kinabuhi nga kalayo apan duna pay kalingkawasan dili kini langit tungod kay ang langit dili man kalayo ug dili sab kini impyerno tungod kay gikan sa kalayo sa impyerno wala na may kaluwasan. Mao kini ang kalayo sa purgaturyo diin ang kalag mag-antos aron siya mahingpit sa dili pa siya mosaka ngadto sa langit nga mao ang puloy-anan “sa mga espiritu sa mga matarong nga nahingpit na” (Heb. 12:23).\nAng pagka-dunay purgaturyo nagsukad sa hustisiya ug kaluoy sa Dios: “Busa maghulat ang Ginoo hangtod nga angay na kamo sa iyang mga kaluoy; ug ikalipay niya ang pagkaluoy kaninyo. Kay ang Ginoo Dios man sa hustisiya” (Isa 30:18). “Ang Dios matarong nga maghuhukom” (Sal. 7:11). “Kay gantihan sa Dios ang tagsatgasa sumala sa iyang binuhatan” (Rom. 2:6). Ngadto sa mga matarong nga niining kinabuhia nakaabot nianang kahingpitan nga angay na silang mahiusa gilayon sa Dios, ang Dios moganti kanila sa kinabuhing dayon (Rom. 2:7). Ngadto sa mga dautan nga hangtod sa ilang kamatayon walay paghinulsol ang ilang dulngan mao ang silot nga walay kataposan (Rom. 2:8). Apan kadtong namatay diha sa kahimtang sa grasya apan dunay gagmayng mansa o buling nga mitapot sa ilang kalag- mga sala sa kakulang sa pailob o dili ba kaha tungod sa tawhanong kahuyang nga dili tinuyoan- itambog ba sila sa Dios ngadto sa impyerno uban sa mga mananapaw ug sa mga mamumuno? Dili! Ang hustisiya ug ang kaluoy sa Dios dili motugot niana “apan ang sulugoon nga wala masayod unsa ang gusto sa iyang agalon, ug makabuhat og butang nga tungod niini angay siyang latoson, silotan sa diriyot nga latos” (Luc. 12:48). Pasudlon ba sab sila dayon ngadto sa langit? Dili usab, ug kini gumikan sa kaputli ug kabalaan sa Dios, “Apan walay bisan unsa nga hugaw makasulod sa siyudad” (Pin. 21:27). Busa kini sila moagi una og usa ka dapit nga linisanan: “pagalinisan ko sila pinaagi sa espiritu sa kalayo ug sa espiritu sa siga” (Isaias 4:4). Ang pagputli sa atong kalag magsugod niining kinabuhia apan kon dili nato makab-ot ang kahingpitan adto kini mahitabo sa purgaturyo. Si Jesus miingon: “Ug timan-i: bilanggoon ka didto hangtod kabayran mo sa hingpit ang imong multa” (Mat. 5:26)."'::jsonb, '[{"objection":"Si San Pablo nag-ingon “gitudloan ko kamo pagkinabuhi sumala sa nasulat” (1 Cor. 4:6) busa kana ra gayong mabasa letra por letra sa Biblia ang tuohan. Matud pa sa Handbook of Catholic Faith p. 461 ang dili nato mabasa ang purgaturyo sa Biblia busa dili kini angay nga tuohan.","response":"Ang dili ipadawat diha sa 1 Cor. 4:6 mao kadtong mga pagtulon-an nga nahisupak sa nasulat (1 Cor. 14:37-38). Ang pulong “purgaturyo” dili mabasa apan ang pagkanaa sa maong dapit o kahimtang gipasabot sa Biblia sumala sa atong nang napamatud-an (2 Mac. 12:43-45, Mat. 12:32, 1 Cor. 3:13-15)."},{"objection":"Dili tinuod nga dunay gagmayng sala nga angay sa gamay ra nga silot tungod kay matud pa sa apostol: “Kay ang naglapas bisan sa usa lamang ka sugo sa Balaod nakalapas sa tanan” (Sant. 2:10). Busa managsama ra ang tanang sala.","response":"Ang gipasabot sa Sant. 2:10 mao ang paglapas sa usa ka sugo sa grabe nga paagi (Sant. 2:11) igo na nga makalaglag sa tawo (Eze. 33:13). Dunay sala nga mosangpot sa kamatayon apan duna say sala nga dili mosangpot sa kamatayon nga ikaampo pa (1 Juan 5:16-17)."},{"objection":"Dili tinuod nga ang mga minatay nag-antos “Ang mga buhi nasayod nga mangamatay sila, apan ang mga patay wala nay mahibaloan bisan unsa… natapos uban kanila ang ilang mga gugma” (Eccl. 9:5-6, Sal. 115:17).","response":"Ang gihisgotan sa Eccl. 9:5-6 nga wala nay kaalam ni kahibalo ug wala nay gugma referido sa lawas sa minatay (Sal. 49:14). Apan ang espiritu kun kalag sa tawo moatubang sa hukmanan sa Dios aron hukman sumala sa iyang nabuhat maayo ba o dautan (Eccl. 12:7, 2 Cor. 5:10)."},{"objection":"Ang pagganti o pagsilot himoon tapos sa hukom. Apan wala pay hukom tungod kay wala pa man mobalik si Cristo “siya mao ang gipili sa Dios paghukom sa mga buhi ug sa mga patay” (Buh. 10:42). Busa kay wa pa may hukom wala pay nalangit o naimpyerno ug labaw nang wala pay na-purgaturyo!","response":"Ang paghukom nga himoon sa pagbalik ni Cristo mao ang hukom nga kinatibuk-an (Buh. 10:42, Mat. 25:31-36). Apan dunay hukom nga tinagsa nga himoon sa takna sa kamatayon (Heb. 9:27, Sir. 11:26). Pruyba nga duna nay hukom kay duna na may nalangit (Pin. 6:9-10)."},{"objection":"Sa kataposang hukom duha ra ka dapit ang gihisgotan, langit ug impyerno ra. Kadtong anaa sa tuo ni Cristo mao ang malangit ug kadtong anaa sa wala mao ang maimpyerno (Mat. 25:31-36). Busa wala gyoy purgaturyo.","response":"Duha ra ka dapit ang gihisgotan sa Mat. 25:31-36 tungod kay nianang higayona mawala na man ang purgaturyo. Sa dili pa himoon ang kataposang hukom pasiunhan kini sa pagbanhaw sa tanang minatay (Jn. 5:28-29)–ug kini naglakip niadtong atua sa purgaturyo nga mahiapil niadtong malangit."},{"objection":"Matud pa ni San Pedro nga “nasayran ninyo nga ang gibayad aron sa pagluwas kaninyo sa daotang pagkinabuhi… dili butang nga kawad-an ug bili sama sa salapi o bulawan, kay giluwas man kamo sa bililhong dugo ni Cristo” (1 Ped. 1:18-19) busa dili maoy makapaluwas kanang pamisa.","response":"Ang Misa mao ang katumanan sa tagna sa usa ka hingpit nga halad nga himoon kada adlaw ug dili kini kabayran (Mal. 1:11). Ang pamisa dili bayad sa misa kondili suhol sa kahago sa pari nga naghalad. Ug kabubut-on sa Dios nga kadtong nag-alagad sa altar may bahin sa halad (1 Cor. 9:13-14) ug si San Pablo midawat og suhol sa iyang kahago (2 Cor. 11:8).\n\nPagtulona-an: Kinahanglan nga ato kanunay nga hinumdoman ang mga kalag sa purgaturyo diha sa atong mga pag-ampo labi na gyod ang pagpamisa alang kanila. Maningkamot usab kita sa paglikay bisan sa gagmayng sala kay kon ato kining madala ngadto sa kamatayon ato kining antosan didto sa purgaturyo ug mohimo usab kita sa pagpamayad sa atong mga sala pinaagi sa pagbuhat og maayo ug sa pagdawat og mga indulhensya nga gihatag sa Simbahan."}]'::jsonb, '["2 Cor. 3:6","Neh. 8:8","Oseas 14:9","Mat. 12:32","1 Cor. 3:13-15","Heb. 12:23","Isa 30:18","Sal. 7:11","Rom. 2:6","Luc. 12:48","Pin. 21:27","Isaias 4:4","Mat. 5:26","1 Cor. 4:6","Sant. 2:10","Buh. 10:42","1 Ped. 1:18-19"]'::jsonb, '["purgatory"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.045Z')
